uniform sampler2D u_texture;   // the input photo
uniform float u_time;          // seconds since start
uniform vec2 u_resolution;     // pixel dimensions
varying vec2 v_uv;             // texture coords, 0..1

void main() {
  vec3 final_color;

  // Calculate a time-varying horizontal offset for the glitch effect
  // The base offset creates the chromatic aberration, and the sin wave adds the "glitch" wobble
  float offset_strength = 0.01 + sin(u_time * 7.0) * 0.005; // Base 0.01, wobbles +/- 0.005

  // Sample red channel with a positive horizontal offset
  final_color.r = texture2D(u_texture, v_uv + vec2(offset_strength, 0.0)).r;

  // Sample green channel at the original UV coordinates
  final_color.g = texture2D(u_texture, v_uv).g;

  // Sample blue channel with a negative horizontal offset
  final_color.b = texture2D(u_texture, v_uv - vec2(offset_strength, 0.0)).b;

  // Clamp the final RGB values to the [0, 1] range and output
  gl_FragColor = vec4(clamp(final_color, 0.0, 1.0), 1.0);
}

